import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import axiosInstance from '../utils/axiosInstance';
import { forgotPasswordSchema, resetPasswordSchema } from '../schemas';

export default function ForgotPassword() {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [emailForReset, setEmailForReset] = useState('');

  const step1 = useFormik({
    initialValues: { email: '' },
    validationSchema: forgotPasswordSchema,
    onSubmit: async ({ email }) => {
      try {
        await axiosInstance.post('/auth/forgot-password', { email });
        setEmailForReset(email);
        toast.success('OTP sent to your email');
        setStep(2);
      } catch (err) {
        toast.error(err.response?.data?.message || 'Failed');
      }
    }
  });

  const step2 = useFormik({
    initialValues: { otp: '', newPassword: '' },
    validationSchema: resetPasswordSchema,
    onSubmit: async (values) => {
      try {
        await axiosInstance.post('/auth/reset-password', { email: emailForReset, ...values });
        toast.success('Password reset successful!');
        navigate('/login');
      } catch (err) {
        toast.error(err.response?.data?.message || 'Failed');
      }
    }
  });

  const errStyle = { color: '#ef4444', fontSize: 12, marginTop: 4 };

  return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center" style={{ background: '#f1f5f9', padding: '16px' }}>
      <div className="w-100" style={{ maxWidth: 420 }}>
        <div className="bg-white rounded-3 shadow p-4 p-md-5">
          <h2 className="mb-1">🔐 Reset Password</h2>
          {step === 1 ? (
            <form onSubmit={step1.handleSubmit}>
              <p className="text-secondary mb-4" style={{ fontSize: 14 }}>Enter your registered email to receive an OTP.</p>
              <div className="mb-3">
                <label className="form-label fw-semibold" style={{ fontSize: 13 }}>Email</label>
                <input name="email" type="email" className="form-control" placeholder="Email" {...step1.getFieldProps('email')} />
                {step1.touched.email && step1.errors.email && <div style={errStyle}>{step1.errors.email}</div>}
              </div>
              <button type="submit" className="btn w-100" style={{ background: '#3b82f6', color: '#fff', fontWeight: 700, padding: '12px' }}>
                Send OTP
              </button>
            </form>
          ) : (
            <form onSubmit={step2.handleSubmit}>
              <p className="text-secondary mb-4" style={{ fontSize: 14 }}>Enter the OTP sent to <strong>{emailForReset}</strong></p>
              <div className="mb-3">
                <label className="form-label fw-semibold" style={{ fontSize: 13 }}>OTP</label>
                <input name="otp" className="form-control" placeholder="6-digit OTP" maxLength={6} {...step2.getFieldProps('otp')} />
                {step2.touched.otp && step2.errors.otp && <div style={errStyle}>{step2.errors.otp}</div>}
              </div>
              <div className="mb-4">
                <label className="form-label fw-semibold" style={{ fontSize: 13 }}>New Password</label>
                <input name="newPassword" type="password" className="form-control" placeholder="New Password" {...step2.getFieldProps('newPassword')} />
                {step2.touched.newPassword && step2.errors.newPassword && <div style={errStyle}>{step2.errors.newPassword}</div>}
              </div>
              <button type="submit" className="btn w-100" style={{ background: '#3b82f6', color: '#fff', fontWeight: 700, padding: '12px' }}>
                Reset Password
              </button>
            </form>
          )}
          <p className="text-center mt-3" style={{ fontSize: 13 }}>
            <Link to="/login" style={{ color: '#3b82f6' }}>← Back to Login</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
